BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?parentReq ?parentName ?depType ?childReq ?childName WHERE {
  ?dep rdf:type ?depType .
  FILTER(?depType IN (vocab:satisfy, vocab:verify, vocab:refine))

  # The Interface Requirements and its children
  VALUES ?interfaceParent {
    <http://api.koneksys.com/cameo/TMT/tmt%20requirement/TMT::Project::Work%2520Packages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specification::TMT%2520Requirements%2520imported%2520from%2520DOORS::DRD%2520APS::APS%2520Requirements::Interface%2520Requirements>
  }

  # Get the Interface Requirements itself or its children
  { ?childReq = ?interfaceParent }
  UNION
  { ?interfaceParent vocab:Element_ownedElement+ ?childReq . ?childReq rdf:type vocab:tmt%20requirement . }

  # Find dependencies where child is client (being satisfied/verified/refined by parent)
  ?dep vocab:Dependency_client ?childReq .
  ?dep vocab:Dependency_supplier ?parentReq .
  ?parentReq rdf:type vocab:tmt%20requirement .

  OPTIONAL { ?parentReq vocab:NamedElement_name ?parentName }
  OPTIONAL { ?childReq vocab:NamedElement_name ?childName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?parentReq ?parentName ?depType ?childReq ?childName WHERE {
  ?dep rdf:type ?depType .
  FILTER(?depType IN (vocab:satisfy, vocab:verify, vocab:refine))

  # The Interface Requirements 
  BIND(<http://api.koneksys.com/cameo/TMT/tmt%20requirement/TMT::Project::Work%2520Packages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specification::TMT%2520Requirements%2520imported%2520from%2520DOORS::DRD%2520APS::APS%2520Requirements::Interface%2520Requirements> AS ?interfaceParent)

  # Get the Interface Requirements itself or its children
  { 
    BIND(?interfaceParent AS ?childReq) 
  }
  UNION
  { 
    ?interfaceParent vocab:Element_ownedElement+ ?childReq . 
    ?childReq rdf:type vocab:tmt%20requirement . 
  }

  # Find dependencies where child is client (being satisfied/verified/refined by parent)
  ?dep vocab:Dependency_client ?childReq .
  ?dep vocab:Dependency_supplier ?parentReq .
  ?parentReq rdf:type vocab:tmt%20requirement .

  OPTIONAL { ?parentReq vocab:NamedElement_name ?parentName }
  OPTIONAL { ?childReq vocab:NamedElement_name ?childName }
}
LIMIT 50

